import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { TimesheetData, DayEntry, LeaveType, Totals } from './types';
import { DAYS } from './constants';
import { generatePdf } from './services/pdfGenerator';
import Header from './components/Header';
import TimesheetRow from './components/TimesheetRow';
import TotalsDisplay from './components/TotalsDisplay';

const employeeOptions = ['Jonny Hogg','Mike Grant', 'Barry Bown', 'Nick Saxton','Daz Gillespie', 'Luke Simpson', 'Dan Smith',   'Other'];
const siteOptions = ['Workshop', 'Templeborough', 'Brigg', 'Vitritech', 'Technical Absorbent', 'TBM Cover', 'Other'];

const getDefaultTimesheetData = (): TimesheetData => ({
    employeeName: '',
    weekEndingDate: new Date().toISOString().substring(0, 10),
    times: DAYS.map(day => ({ day, reg: 0.00, ot15: 0.00, ot2: 0.00, leaveType: 'none', siteSelection: '', site: '' }))
});

const App: React.FC = () => {
    const [timesheetData, setTimesheetData] = useState<TimesheetData>(getDefaultTimesheetData);
    const [employeeSelection, setEmployeeSelection] = useState<string>(''); // For dropdown UI

    const [statusMessage, setStatusMessage] = useState({ text: '', isError: false });
    const [validationErrors, setValidationErrors] = useState<Record<string, boolean>>({});

    useEffect(() => {
        showStatus('New timesheet. Fill in your hours to begin.', false);
    }, []);

    const showStatus = (text: string, isError: boolean) => {
        setStatusMessage({ text, isError });
        setTimeout(() => {
            setStatusMessage({ text: '', isError: false });
        }, 5000);
    };

    const handleHeaderChange = useCallback((field: 'employeeSelection' | 'employeeName' | 'weekEndingDate', value: string) => {
        if (field === 'employeeSelection') {
            setEmployeeSelection(value);
            if (value === 'Other') {
                setTimesheetData(prev => ({ ...prev, employeeName: '' }));
            } else {
                setTimesheetData(prev => ({ ...prev, employeeName: value }));
            }
        } else { // Handles 'employeeName' from the 'Other' input, and 'weekEndingDate'
            setTimesheetData(prevData => ({ ...prevData, [field]: value }));
        }
    }, []);

    const handleTimesheetChange = useCallback((index: number, field: keyof DayEntry, value: string | number | LeaveType) => {
        if (field === 'site' || field === 'siteSelection') {
            setValidationErrors(prev => {
                const newErrors = { ...prev };
                delete newErrors[`site-${index}`];
                return newErrors;
            });
        }

        setTimesheetData(prevData => {
            const newTimes = [...prevData.times];
            const dayEntry = { ...newTimes[index] };

            if (field === 'leaveType') {
                dayEntry.leaveType = value as LeaveType;

                // Clear any existing site validation error for this row
                setValidationErrors(prev => {
                    const newErrors = { ...prev };
                    delete newErrors[`site-${index}`];
                    return newErrors;
                });

                // Reset hours first
                dayEntry.reg = 0.00;
                dayEntry.ot15 = 0.00;
                dayEntry.ot2 = 0.00;

                // Set hours and site based on leave type
                if (value === 'al8') {
                    dayEntry.reg = 8.00;
                    dayEntry.site = 'HOLIDAY';
                    dayEntry.siteSelection = 'Other'; // Set to Other to ensure it matches the text input behavior
                } else if (value === 'al4') {
                    dayEntry.reg = 4.00;
                    dayEntry.site = 'HOLIDAY';
                    dayEntry.siteSelection = 'Other';
                } else if (value === 'bh8') {
                    dayEntry.reg = 8.00;
                    dayEntry.site = 'BANK HOLIDAY';
                    dayEntry.siteSelection = 'Other';
                } else if (value === 'sl') {
                    dayEntry.reg = 8.00;
                    dayEntry.site = 'SICK';
                    dayEntry.siteSelection = 'Other';
                } else if (value === 'none') {
                    // When changing back to 'none', clear the auto-populated site fields
                    if (dayEntry.site === 'HOLIDAY' || dayEntry.site === 'SICK' || dayEntry.site === 'BANK HOLIDAY') {
                        dayEntry.site = '';
                        dayEntry.siteSelection = '';
                    }
                }
            } else if (field === 'siteSelection') {
                dayEntry.siteSelection = value as string;
                if (value === 'Other') {
                    dayEntry.site = '';
                } else {
                    dayEntry.site = value as string;
                }

                // Reset hours on any site change for a clean slate
                dayEntry.reg = 0.00;
                dayEntry.ot15 = 0.00;
                dayEntry.ot2 = 0.00;

                // When a site is selected, auto-populate hours based on the day.
                if (value) { // A site was selected (i.e., value is not "")
                    const dayName = dayEntry.day;

                    if (dayName === 'Saturday') {
                        dayEntry.ot15 = 4.00;
                        dayEntry.ot2 = 4.00;
                    } else if (dayName === 'Sunday') {
                        dayEntry.ot2 = 8.00;
                    } else { // Weekdays
                        dayEntry.reg = 8.00;
                    }

                    // Auto-populate additional OT hours based on specific sites
                    if (value === 'Brigg') {
                        dayEntry.ot15 += 1.00;
                    }
                    if (value === 'Technical Absorbent') {
                        dayEntry.ot2 += 1.00;
                    }
                }

            } else if (typeof value === 'string' && ['reg', 'ot15', 'ot2'].includes(field)) {
                const numValue = parseFloat(value) || 0;
                (dayEntry as any)[field] = Math.max(0, parseFloat(numValue.toFixed(2)));
            } else {
                (dayEntry as any)[field] = value;
            }

            newTimes[index] = dayEntry;
            return { ...prevData, times: newTimes };
        });
    }, []);

    const totals: Totals = useMemo(() => {
        return timesheetData.times.reduce((acc, day) => {
            acc.totalReg += day.reg;
            acc.totalOT15 += day.ot15;
            acc.totalOT2 += day.ot2;
            acc.totalEffective += day.reg + (day.ot15 * 1.5) + (day.ot2 * 2);
            return acc;
        }, { totalReg: 0, totalOT15: 0, totalOT2: 0, totalEffective: 0 });
    }, [timesheetData.times]);

    const handleSaveAndGeneratePdf = () => {
        if (!timesheetData.employeeName.trim()) {
            showStatus('Employee Name is required before generating a PDF.', true);
            const employeeNameInput = document.getElementById('employeeName') || document.getElementById('employeeNameSelect');
            if (employeeNameInput) {
                employeeNameInput.focus();
            }
            return;
        }

        const errors: Record<string, boolean> = {};
        let firstErrorIndex = -1;

        timesheetData.times.forEach((dayEntry, index) => {
            const hasHours = dayEntry.reg > 0 || dayEntry.ot15 > 0 || dayEntry.ot2 > 0;
            const hasSite = !!dayEntry.site.trim();

            if (hasHours && !hasSite) {
                errors[`site-${index}`] = true;
                if (firstErrorIndex === -1) {
                    firstErrorIndex = index;
                }
            }
        });

        if (Object.keys(errors).length > 0) {
            setValidationErrors(errors);
            const firstErrorDay = timesheetData.times[firstErrorIndex];
            showStatus(`Work Site is required for ${firstErrorDay.day} when hours are entered.`, true);
            const siteInput = document.getElementById(`site-select-${firstErrorIndex}`) || document.getElementById(`site-input-${firstErrorIndex}`);
            if (siteInput) {
                siteInput.focus();
                siteInput.scrollIntoView({ behavior: 'smooth', block: 'center' });
            }
            return;
        }

        setValidationErrors({}); // Clear errors if validation passes

        showStatus('Generating PDF...', false);
        try {
            generatePdf(timesheetData, totals);
            showStatus('PDF generated successfully! The form has been reset.', false);
            setTimesheetData(getDefaultTimesheetData());
            setEmployeeSelection(''); // Reset dropdown as well
        } catch (error) {
            console.error("PDF Generation Error:", error);
            const message = error instanceof Error ? error.message : 'See console for details.';
            showStatus(`Error generating PDF: ${message}`, true);
        }
    };

    return (
        <div id="timesheet-container" className="max-w-4xl mx-auto bg-white dark:bg-gray-800 shadow-xl rounded-xl p-4 sm:p-8">
            <h1 className="text-2xl font-extrabold tracking-wider text-white mb-6 text-center bg-black py-3 px-6 rounded-xl">RTD MECHANICAL LTD</h1>
            <Header
                employeeName={timesheetData.employeeName}
                weekEndingDate={timesheetData.weekEndingDate}
                onHeaderChange={handleHeaderChange}
                employeeSelection={employeeSelection}
                employeeOptions={employeeOptions}
            />
            {statusMessage.text && (
                <div className={`text-sm font-medium text-right mb-4 transition-opacity duration-300 ${statusMessage.isError ? 'text-red-500 dark:text-red-400' : 'text-blue-600 dark:text-blue-400'}`}>
                    {statusMessage.text}
                </div>
            )}

            <div className="grid grid-cols-12 text-xs sm:text-sm font-bold text-gray-600 dark:text-gray-300 bg-blue-50 dark:bg-gray-700/50 rounded-t-lg py-3 px-2 shadow-sm">
                <div className="col-span-2 sm:col-span-3">Day</div>
                <div className="col-span-3 text-center">
                    <span className="hidden sm:inline">Regular (1x)</span>
                    <span className="sm:hidden">Reg</span>
                </div>
                <div className="col-span-2 text-center">
                    <span className="hidden sm:inline">OT (1.5x)</span>
                    <span className="sm:hidden">OT 1.5x</span>
                </div>
                <div className="col-span-2 text-center">
                    <span className="hidden sm:inline">OT (2x)</span>
                    <span className="sm:hidden">OT 2x</span>
                </div>
                <div className="col-span-3 sm:col-span-2 text-center">Leave</div>
            </div>

            <div id="day-entries" className="border border-gray-200 dark:border-gray-700 rounded-b-lg divide-y divide-gray-200 dark:divide-gray-700 mb-8">
                {timesheetData.times.map((dayData, index) => (
                    <TimesheetRow
                        key={dayData.day}
                        dayData={dayData}
                        index={index}
                        onTimesheetChange={handleTimesheetChange}
                        isSiteInvalid={!!validationErrors[`site-${index}`]}
                        siteOptions={siteOptions}
                    />
                ))}
            </div>

            <TotalsDisplay totals={totals} />

            <div className="flex flex-col sm:flex-row justify-end items-center mt-8 pt-4 border-t border-gray-100 dark:border-gray-700">
                <button
                    id="saveButton"
                    onClick={handleSaveAndGeneratePdf}
                    className="w-full sm:w-auto px-6 py-2 bg-blue-600 text-white font-semibold rounded-lg shadow-md hover:bg-blue-700 transition duration-150 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                >
                    Save & Generate PDF
                </button>
            </div>
        </div>
    );
};

export default App;

import React from 'react';
import { DayEntry, LeaveType } from '../types';

interface TimesheetRowProps {
    dayData: DayEntry;
    index: number;
    onTimesheetChange: (index: number, field: keyof DayEntry, value: string | number | LeaveType) => void;
    isSiteInvalid: boolean;
    siteOptions: string[];
}

const formatHoursForDisplay = (num: number): string => {
    if (typeof num !== 'number' || isNaN(num) || num === 0) return '';
    const preciseNum = parseFloat(num.toFixed(2));
    if (preciseNum % 1 === 0) {
        return preciseNum.toFixed(0);
    }
    if ((preciseNum * 10) % 1 === 0) {
        return preciseNum.toFixed(1);
    }
    return preciseNum.toString();
};

const TimesheetRow: React.FC<TimesheetRowProps> = ({ dayData, index, onTimesheetChange, isSiteInvalid, siteOptions }) => {
    const { day, reg, ot15, ot2, leaveType, siteSelection, site } = dayData;

    const isLeaveSelected = leaveType !== 'none';
    const isSiteSelected = !!site.trim();
    const areHoursDisabled = isLeaveSelected || !isSiteSelected;
    const isWeekday = !['Saturday', 'Sunday'].includes(day);
    const needsHighlight = isWeekday && !siteSelection && !isLeaveSelected;

    const showOtherSiteInput = siteSelection === 'Other' || isLeaveSelected;

    let rowClass = 'group transition-colors duration-200';
    if (leaveType.startsWith('al') || leaveType === 'bh8') {
        rowClass += ' bg-green-50 dark:bg-green-900/50 hover:bg-green-100 dark:hover:bg-green-900/75';
    } else if (leaveType === 'sl') {
        rowClass += ' bg-yellow-50 dark:bg-yellow-900/50 hover:bg-yellow-100 dark:hover:bg-yellow-900/75';
    } else {
        rowClass += ' hover:bg-gray-50 dark:hover:bg-gray-700/50';
    }

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;

        if (['reg', 'ot15', 'ot2'].includes(name)) {
            if (value === '' || /^[0-9]*\.?[0-9]{0,2}$/.test(value)) {
                onTimesheetChange(index, name as keyof DayEntry, value);
            }
        } else {
            onTimesheetChange(index, name as keyof DayEntry, value);
        }
    };

    return (
        <div className={`p-2 ${rowClass}`}>
             <div className="mb-2">
                <label htmlFor={`site-select-${index}`} className="text-xs font-medium text-gray-500 dark:text-gray-400 mb-1 block">Work Site:</label>
                <div className="flex flex-col sm:flex-row gap-2">
                    {!isLeaveSelected && (
                        <select
                            id={`site-select-${index}`}
                            name="siteSelection"
                            value={siteSelection}
                            onChange={handleInputChange}
                            className={`p-2 border rounded-md text-sm focus:border-blue-500 bg-white dark:bg-gray-700 dark:text-white dark:border-gray-600 transition-shadow duration-300 ${isSiteInvalid ? 'border-red-500 ring-1 ring-red-500' : 'border-gray-200'} ${showOtherSiteInput ? 'sm:w-1/2' : 'w-full'} ${needsHighlight ? 'animate-pulse-glow' : ''}`}
                        >
                            <option value="">Select a site to enter hours...</option>
                            {siteOptions.map(option => <option key={option} value={option}>{option}</option>)}
                        </select>
                    )}
                    {showOtherSiteInput && (
                        <input
                            type="text"
                            id={`site-input-${index}`}
                            value={site}
                            name="site"
                            onChange={handleInputChange}
                            placeholder={isLeaveSelected ? "Leave Details (e.g. HOLIDAY)" : "Enter Custom Site"}
                            className={`flex-grow p-2 border rounded-md text-sm focus:border-blue-500 dark:bg-gray-700 dark:text-white dark:border-gray-600 ${isSiteInvalid ? 'border-red-500 ring-1 ring-red-500' : 'border-gray-200'}`}
                        />
                    )}
                </div>
            </div>

            <div className="grid grid-cols-12 items-center">
                <div className="col-span-2 sm:col-span-3 font-semibold text-gray-700 dark:text-gray-200 text-sm">
                    <span className="hidden sm:inline">{day}</span>
                    <span className="sm:hidden">{day.substring(0, 3)}</span>
                </div>

                <div className="col-span-3 flex justify-center px-1">
                    <input type="number" min="0" step="0.01" value={formatHoursForDisplay(reg)}
                        name="reg"
                        onChange={handleInputChange}
                        placeholder="-"
                        className="w-full p-2 border rounded-md text-sm text-center focus:border-blue-500 disabled:bg-gray-100 disabled:text-gray-400 disabled:cursor-not-allowed dark:bg-gray-700 dark:text-white dark:border-gray-600 dark:disabled:bg-gray-600 dark:disabled:text-gray-400"
                        disabled={areHoursDisabled}
                    />
                </div>

                <div className="col-span-2 flex justify-center px-1">
                    <input type="number" min="0" step="0.01" value={formatHoursForDisplay(ot15)}
                        name="ot15"
                        onChange={handleInputChange}
                        placeholder="-"
                        className="w-full p-2 border rounded-md text-sm text-center focus:border-blue-500 disabled:bg-gray-100 disabled:text-gray-400 disabled:cursor-not-allowed dark:bg-gray-700 dark:text-white dark:border-gray-600 dark:disabled:bg-gray-600 dark:disabled:text-gray-400"
                        disabled={areHoursDisabled}
                    />
                </div>

                <div className="col-span-2 flex justify-center px-1">
                    <input type="number" min="0" step="0.01" value={formatHoursForDisplay(ot2)}
                        name="ot2"
                        onChange={handleInputChange}
                        placeholder="-"
                        className="w-full p-2 border rounded-md text-sm text-center focus:border-blue-500 disabled:bg-gray-100 disabled:text-gray-400 disabled:cursor-not-allowed dark:bg-gray-700 dark:text-white dark:border-gray-600 dark:disabled:bg-gray-600 dark:disabled:text-gray-400"
                        disabled={areHoursDisabled}
                    />
                </div>

                <div className="col-span-3 sm:col-span-2 flex justify-center">
                    <select
                        name="leaveType"
                        value={leaveType}
                        onChange={handleInputChange}
                        className="w-full p-2 border rounded-md text-xs text-center bg-white focus:ring-blue-500 focus:border-blue-500 dark:bg-gray-700 dark:text-white dark:border-gray-600"
                    >
                        <option value="none">None</option>
                        <option value="al8">AL (8h)</option>
                        <option value="al4">AL (4h)</option>
                        <option value="bh8">BANKHOL(8)</option>
                        <option value="sl">SL (8h)</option>
                    </select>
                </div>
            </div>
        </div>
    );
};

export default React.memo(TimesheetRow);

import { TimesheetData, Totals } from '../types';

declare global {
    interface Window {
        jspdf: any;
    }
}

export const generatePdf = (data: TimesheetData, totals: Totals) => {
    // Accessing jspdf from the CDN global loaded in index.html
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF();

    // Setup basic styles
    const primaryColor = [30, 58, 138]; // blue-900

    // Header Rectangle
    doc.setFillColor(0, 0, 0);
    doc.rect(0, 0, 210, 35, 'F');

    // Header Text
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(22);
    doc.setFont('helvetica', 'bold');
    doc.text('RTD MECHANICAL LTD', 105, 20, { align: 'center' });

    doc.setFontSize(12);
    doc.setFont('helvetica', 'normal');
    doc.text('Weekly Timesheet Report', 105, 30, { align: 'center' });

    // Info Section
    doc.setTextColor(0, 0, 0);
    doc.setFontSize(10);
    doc.setFont('helvetica', 'bold');
    doc.text('EMPLOYEE NAME:', 15, 50);
    doc.setFont('helvetica', 'normal');
    doc.text(data.employeeName || 'Not Specified', 55, 50);

    doc.setFont('helvetica', 'bold');
    doc.text('WEEK ENDING:', 15, 58);
    doc.setFont('helvetica', 'normal');
    doc.text(data.weekEndingDate, 50, 58);

    // Table Data Mapping
    const tableData = data.times.map(row => {
        let leaveLabel = '-';
        if (row.leaveType === 'al8') leaveLabel = 'Annual Leave (8h)';
        else if (row.leaveType === 'al4') leaveLabel = 'Annual Leave (4h)';
        else if (row.leaveType === 'bh8') leaveLabel = 'Bank Holiday (8h)';
        else if (row.leaveType === 'sl') leaveLabel = 'Sick Leave (8h)';

        return [
            row.day,
            row.site || '-',
            row.reg > 0 ? row.reg.toFixed(2) : '-',
            row.ot15 > 0 ? row.ot15.toFixed(2) : '-',
            row.ot2 > 0 ? row.ot2.toFixed(2) : '-',
            row.leaveType !== 'none' ? leaveLabel : 'Work'
        ];
    });

    // Draw Table
    (doc as any).autoTable({
        startY: 65,
        head: [['Day', 'Work Site / Description', 'Regular', 'OT 1.5x', 'OT 2.0x', 'Type']],
        body: tableData,
        theme: 'grid',
        headStyles: { fillColor: primaryColor, textColor: 255, fontStyle: 'bold' },
        styles: { fontSize: 9, halign: 'left' },
        columnStyles: {
            2: { halign: 'center' },
            3: { halign: 'center' },
            4: { halign: 'center' },
            5: { halign: 'center' },
        }
    });

    const finalY = (doc as any).lastAutoTable.cursor.y + 15;

    // Totals Section
    doc.setFontSize(11);
    doc.setFont('helvetica', 'bold');
    doc.text('TOTALS', 15, finalY);

    doc.setFont('helvetica', 'normal');
    doc.text(`Total Regular:`, 15, finalY + 8);
    doc.text(totals.totalReg.toFixed(2), 55, finalY + 8);

    doc.text(`Total OT 1.5x:`, 15, finalY + 15);
    doc.text(totals.totalOT15.toFixed(2), 55, finalY + 15);

    doc.text(`Total OT 2.0x:`, 15, finalY + 22);
    doc.text(totals.totalOT2.toFixed(2), 55, finalY + 22);

    // Highlight Box for Effective Hours
    doc.setFillColor(240, 249, 255);
    doc.rect(130, finalY - 5, 65, 30, 'F');
    doc.setDrawColor(30, 58, 138);
    doc.rect(130, finalY - 5, 65, 30, 'S');

    doc.setTextColor(30, 58, 138);
    doc.setFontSize(10);
    doc.text('EFFECTIVE TOTAL', 162.5, finalY + 5, { align: 'center' });
    doc.setFontSize(18);
    doc.text(totals.totalEffective.toFixed(2), 162.5, finalY + 18, { align: 'center' });

    // Save PDF
    const fileName = `Timesheet_${data.employeeName.replace(/\s+/g, '_')}_${data.weekEndingDate}.pdf`;
    doc.save(fileName);
};

