                            placeholder="Specify site / work details..."
                            className={`flex-1 p-2.5 border rounded-lg text-sm dark:bg-gray-700 transition-all ${isSiteInvalid ? 'border-red-500 bg-red-50' : 'border-gray-200 focus:border-blue-500'}`}
                        />
                    )}
                </div>
            </div>

            <div className="grid grid-cols-4 gap-3">
                <div className="space-y-1">
                    <label className="text-[10px] font-bold text-gray-400 uppercase text-center block">Reg</label>
                    <input type="number" name="reg" value={formatHours(reg)}
                        onChange={handleFieldChange} placeholder="0.0"
                        className="w-full p-2 bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-lg text-center font-bold"
                    />
                </div>
                <div className="space-y-1">
                    <label className="text-[10px] font-bold text-gray-400 uppercase text-center block">OT 1.5</label>
                    <input type="number" name="ot15" value={formatHours(ot15)}
                        onChange={handleFieldChange} placeholder="0.0"
                        className="w-full p-2 bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-lg text-center font-bold text-blue-600"
                    />
                </div>
                <div className="space-y-1">
                    <label className="text-[10px] font-bold text-gray-400 uppercase text-center block">OT 2.0</label>
                    <input type="number" name="ot2" value={formatHours(ot2)}
                        onChange={handleFieldChange} placeholder="0.0"
                        className="w-full p-2 bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-lg text-center font-bold text-red-600"
                    />
                </div>
                <div className="space-y-1">
                    <label className="text-[10px] font-bold text-gray-400 uppercase text-center block">Leave</label>
                    <select
                        name="leaveType"
                        value={leaveType}
                        onChange={handleFieldChange}
                        className="w-full p-2 bg-gray-100 dark:bg-gray-600 border-none rounded-lg text-xs font-bold text-center"
                    >
                        <option value="none">-</option>
                        <option value="al8">AL (8)</option>
                        <option value="al4">AL (4)</option>
                        <option value="bh8">BH (8)</option>
                        <option value="sl">SL (8)</option>
                    </select>
                </div>
            </div>
        </div>
    );
};

export default React.memo(TimesheetRow);
